module top_module(
    input u,
    input v,
    input w,
    input s0,
    input s1,
    output m
    );wire sel_out;

    // Implementing (~s0 & u) | (s0 & v)
    assign sel_out = (~s0 & u) | (s0 & v);

    // Implementing (~s1 & sel_out) | (s1 & w)
    assign m = (~s1 & sel_out) | (s1 & w);

endmodule
